/** NOTE: THere are various configuration options available
 * as a 2nd parameter to renderToHTML. However, only 1 is
 * valid when used to purely render:
 * 
 * includeStles - adds <style> before the output (boolean)
 */

// The render fn is supplied by uibuilder
const renderToHTML = RED.util.uib.renderToHTML

// Convert the input payload
const out = msg.payload = renderToHTML(msg.payload)

// Output 2 differe variations
return [
    // Send this to a uib-element node set to HTML output
    // and then on to a uibuilder node
    msg,

    // Send this one to a uib-sidebar node containing
    // a <div id="more">
    {
        sidebar: {
            more: {
                innerHTML: out,
            },
        },
    },
]

