// Give VS Code IntelliSense for uibuilder
/// <reference path="../types/uibuilder.d.ts" />

const defaultData = {
    standard: {
        string: "R1C1",
        "odd-prop-name": 42,
        "i-am": true,
        "date": new Date(),
        "array": [1, "a", 2, true, 3],
    },
    functions: {
        myCustomFn: function aDifferentName() { return true },
        arrowFn: () => { return true },
        asyncFn: async function aDifferentName2() { return true },
        asyncArrowFn: async () => { return true },
        generatorFn: function* mygeny() { yield 'Hello' },
        asyncGeneratorFn: async function* mygeny2() { yield 'Goodby' },
    },
    specials: {
        "null": null,
        "undefined": undefined,
        "NaN": NaN,
        "Infinity": Infinity,
        "bigint": 9007199254740992n, // Larger than Number.MAX_SAFE_INTEGER
        "symbol": Symbol("mySymbol"),
        "map": new Map([['key', 'value']]),
        "set": new Set([1, 2, 3]),
        "weakmap": new WeakMap([[{ id: 2 }, 'metadata']]),
        "weakset": new WeakSet([{ id: 1 }, { id: 2 }]),
        "regex": /test/gi,
        "error": new Error('Process failed'),
        "arrayBuffer": new ArrayBuffer(8), // a buffer of 8 bytes
        "uint8array": new Uint8Array([10, 20, 30]), // typed array buffer
        "url": new URL('https://example.come/some/path?x=this,y=that'),
        "promise": new Promise(() => { }),
    },
    // Circular reference example
    circular: {}
}
defaultData.circular.self = defaultData

// Get a reference to the json-viewer element
const jv1 = document.getElementById('jv1')
const jv2 = document.getElementById('jv2')
// console.log('JsonViewer element', jv1)

/** For some things, we need to wait for everything to be loaded before using components from JavaScript */
addEventListener("DOMContentLoaded", (event) => {
    // What version are we using? This is static so we use the class global reference
    console.log('Json Viewer version: ', JsonViewer.version)

    // Load some initial test data into the viewer
    jv1.data = defaultData
    jv2.data = defaultData
})

// Listen for incoming messages from Node-RED and action
uibuilder.onChange('msg', (msg) => {
    console.log('Data received', msg)
    jv3.data = JSON.parse(msg.payload)
})

// NB: You could also use uibuilder's syntaxHighlight fn which will automatically use the JsonViewer renderer if available.
// $('#more').innerHTML = `<pre><code>${uib.syntaxHighlight(defaultData)}</code></pre>`

// We don't need this if using with uibuilder, included for information only. Listen for changes to the viewer and log them to the console
// Only fires if the component is set to be editable, and a change is made by the user.
addEventListener('json-viewer:change', (evt) => {
    // evt.detail.data contains the updated data, and evt.detail.id contains the id of the viewer that was changed.
    console.log('json-viewer:change event', evt.detail)
    // This is the one we set to be editable, so we know the change came from that one.
    if (evt.detail.id === 'jv2') {
        // Note that the ORIGINAL data as well as the element's data variable are BOTH CHANGED
        // by any edits.
        console.log('Updated data from jv2', jv2.data, defaultData)
    }
})
